module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] sum1, sum2, sum3, sum4;
    wire [7:0] carry;

    // Instantiate 8-bit adders
    assign {carry[0], sum1} = a[7:0] + b[7:0] + Cin;
    assign {carry[1], sum2} = a[15:8] + b[15:8] + carry[0];
    assign {carry[2], sum3} = a[23:16] + b[23:16] + carry[1];
    assign {Co, sum4} = a[31:24] + b[31:24] + carry[2];

    // Concatenate the partial sums to form the final 16-bit sum
    assign y = {sum4, sum3, sum2, sum1};

endmodule
